insert into cases (code, title, summary, difficulty, estimated_minutes, status) values
('CLOCK_317', '《三点十七分的钟声》', '钟楼、镇长失踪、红手套、旧矿难', 'MEDIUM', 20, 'ACTIVE'),
('ROSE_ROOM_8', '《玫瑰旅馆的第八间房》', '旅馆、密室、账本、第八把钥匙、双重身份', 'MEDIUM', 20, 'ACTIVE'),
('FOG_LAST_FERRY', '《雾港最后一班船》', '港口、无人渡船、船票名单、失踪人口、假身份', 'HARD', 22, 'ACTIVE');
insert into case_rules (case_id, rule_code, rule_text, truth_meaning, display_order) select id, 'CLOCK_RULE_TIME', '钟楼所有机械钟每天只会自动校准一次。', '三点十七分的钟声若被多人听见，说明有人手动拨动了钟锤。', 1 from cases where code = 'CLOCK_317';
insert into case_rules (case_id, rule_code, rule_text, truth_meaning, display_order) select id, 'CLOCK_RULE_GLOVE', '红手套是镇政厅冬季执勤物资，领用必须登记。', '红手套能把嫌疑人限定在接触过镇政厅仓库的人。', 2 from cases where code = 'CLOCK_317';
insert into case_rules (case_id, rule_code, rule_text, truth_meaning, display_order) select id, 'CLOCK_RULE_MINE', '旧矿难档案只保存在钟楼地下室和镇政厅档案柜。', '知晓矿难细节的人必然进入过关键地点。', 3 from cases where code = 'CLOCK_317';
insert into case_rules (case_id, rule_code, rule_text, truth_meaning, display_order) select id, 'ROSE_RULE_KEY', '玫瑰旅馆第八间房有两把外形相同的钥匙。', '钥匙编号不能单独证明进入者身份。', 1 from cases where code = 'ROSE_ROOM_8';
insert into case_rules (case_id, rule_code, rule_text, truth_meaning, display_order) select id, 'ROSE_RULE_LEDGER', '夜班账本每页都由当班柜员签名。', '账本缺页意味着有人伪造了入住时间线。', 2 from cases where code = 'ROSE_ROOM_8';
insert into case_rules (case_id, rule_code, rule_text, truth_meaning, display_order) select id, 'ROSE_RULE_ROOM', '第八间房的窗栓只能从房内扣上。', '密室表象必须通过身份或钥匙漏洞解释。', 3 from cases where code = 'ROSE_ROOM_8';
insert into case_rules (case_id, rule_code, rule_text, truth_meaning, display_order) select id, 'FOG_RULE_FERRY', '雾港最后一班船必须留下船票副联。', '无人渡船仍有可追溯的乘客名单。', 1 from cases where code = 'FOG_LAST_FERRY';
insert into case_rules (case_id, rule_code, rule_text, truth_meaning, display_order) select id, 'FOG_RULE_TIDE', '大雾夜退潮后，东码头无法靠岸。', '声称从东码头下船的证词不成立。', 2 from cases where code = 'FOG_LAST_FERRY';
insert into case_rules (case_id, rule_code, rule_text, truth_meaning, display_order) select id, 'FOG_RULE_ALIAS', '港务处临时工牌必须绑定真实住址。', '假身份会在住址和船票名单之间露出矛盾。', 3 from cases where code = 'FOG_LAST_FERRY';
