insert into case_npcs (case_id, location_id, code, name, role_name, personality, speaking_style, unlock_stage) select c.id, l.id, 'CLOCK_WATCHMAN', '梁守钟', '守钟人', '谨慎、守旧、对钟楼机械极为敏感。', '慢声慢气，常用钟表比喻。', 1 from cases c join case_locations l on l.case_id = c.id and l.code = 'CLOCK_TOWER' where c.code = 'CLOCK_317';
