insert into npc_knowledge (npc_id, known_facts, revealable_clue_codes, hidden_facts, forbidden_topics) select n.id, '守钟人知道钟声不是自动报时。', 'CLOCK_TIME_0317_BELL,CLOCK_LOCATION_ARCHIVE_DUST', '他曾替镇长隐瞒钟楼地下室钥匙丢失。', '矿难赔偿私约' from case_npcs n join cases c on c.id = n.case_id where c.code = 'CLOCK_317' and n.code = 'CLOCK_WATCHMAN';
